searchData={"items":[{"type":"module","title":"FacilGuide","doc":"Multilingual tech guide utilities in 5 languages.\n\nHomepage: https://facil.guide","ref":"FacilGuide.html"},{"type":"function","title":"FacilGuide.base_url/0","doc":"","ref":"FacilGuide.html#base_url/0"},{"type":"function","title":"FacilGuide.version/0","doc":"","ref":"FacilGuide.html#version/0"},{"type":"extras","title":"FacilGuide Elixir Utilities","doc":"# FacilGuide Elixir Utilities\n\nMultilingual tech guide utilities for Elixir by [Facil.guide](https://facil.guide). Supports 5 languages.","ref":"readme.html"},{"type":"extras","title":"Installation - FacilGuide Elixir Utilities","doc":"Add `facilguide` to your list of dependencies in `mix.exs`:\n\n```elixir\ndef deps do\n  [\n    {:facilguide, \"~> 0.1.0\"}\n  ]\nend\n```","ref":"readme.html#installation"},{"type":"extras","title":"Usage - FacilGuide Elixir Utilities","doc":"```elixir\nFacilGuide.version()\n# => \"0.1.0\"\n\nFacilGuide.base_url()\n# => \"https://facil.guide\"\n```","ref":"readme.html#usage"},{"type":"extras","title":"Links - FacilGuide Elixir Utilities","doc":"- [Homepage](https://facil.guide)\n- [Documentation](https://facil.guide/en/)\n- [GitHub](https://github.com/arnaudleroy-studio/facilguide-elixir)","ref":"readme.html#links"},{"type":"extras","title":"License - FacilGuide Elixir Utilities","doc":"MIT License. See [LICENSE](LICENSE) for details.","ref":"readme.html#license"}],"proglang":"elixir","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.40.1"}}